 110→// src/wow/protocol/duel.ts
 111→import { PacketReader, PacketWriter } from "wow/protocol/packet";
 112→
 113→export type DuelRequested = {
 114→  initiator: bigint;
 115→  arbiter: bigint;
 116→};
 117→
 118→export type DuelCountdown = {
 119→  timeMs: number;
 120→};
 121→
 122→export type DuelComplete = {
 123→  completed: boolean;
 124→};
 125→
 126→export type DuelWinner = {
 127→  reason: "won" | "fled";
 128→  loser: string;
 129→  winner: string;
 130→};
 131→
 132→export function parseDuelRequested(r: PacketReader): DuelRequested {
 133→  return {
 134→    initiator: r.uint64LE(),
 135→    arbiter: r.uint64LE(),
 136→  };
 137→}
 138→
 139→export function parseDuelCountdown(r: PacketReader): DuelCountdown {
 140→  return { timeMs: r.uint32LE() };
 141→}
 142→
 143→export function parseDuelComplete(r: PacketReader): DuelComplete {
 144→  return { completed: r.uint8() !== 0 };
 145→}
 146→
 147→export function parseDuelWinner(r: PacketReader): DuelWinner {
 148→  const reason = r.uint8() === 0 ? "won" : "fled";
 149→  const loser = r.cString();
 150→  const winner = r.cString();
 151→  return { reason, loser, winner } as const;
 152→}
