 418→export function handleDuelRequested(conn: WorldConn, r: PacketReader): void {
 419→  const duel = parseDuelRequested(r);
 420→  conn.duelArbiter = duel.arbiter;
 421→  conn.pendingRequest = "duel";
 422→  const guidLow = Number(duel.initiator & 0xffffffffn);
 423→  const name = conn.nameCache.get(guidLow) ?? "Unknown";
 424→  conn.onDuelEvent?.({ type: "duel_requested", challenger: name });
 425→}
 426→
 427→export function handleDuelCountdown(conn: WorldConn, r: PacketReader): void {
 428→  const { timeMs } = parseDuelCountdown(r);
 429→  conn.onDuelEvent?.({ type: "duel_countdown", timeMs });
 430→}
 431→
 432→export function handleDuelComplete(conn: WorldConn, r: PacketReader): void {
 433→  const { completed } = parseDuelComplete(r);
 434→  conn.onDuelEvent?.({ type: "duel_complete", completed });
 435→}
 436→
 437→export function handleDuelWinner(conn: WorldConn, r: PacketReader): void {
 438→  const { reason, winner, loser } = parseDuelWinner(r);
 439→  conn.duelArbiter = 0n;
 440→  conn.onDuelEvent?.({ type: "duel_winner", reason, winner, loser });
 441→}
