 764→function formatDuelEvent(event: DuelEvent): string | undefined {
 765→  switch (event.type) {
 766→    case "duel_requested":
 767→      return `[duel] ${event.challenger} challenges you to a duel`;
 768→    case "duel_countdown":
 769→      return `[duel] Duel starting in ${event.timeMs / 1000} seconds`;
 770→    case "duel_complete":
 771→      return event.completed ? undefined : "[duel] Duel interrupted";
 772→    case "duel_winner":
 773→      return event.reason === "won"
 774→        ? `[duel] ${event.winner} has defeated ${event.loser} in a duel`
 775→        : `[duel] ${event.loser} has fled from ${event.winner} in a duel`;
 776→    case "duel_out_of_bounds":
 777→      return "[duel] Out of bounds — return to the duel area";
 778→    case "duel_in_bounds":
 779→      return "[duel] Back in bounds";
 780→  }
 781→}
