  1→import type { Socket, TCPSocketListener } from "bun";
  2→import { createHmac, createCipheriv, createDecipheriv } from "node:crypto";
  3→import { PacketReader, PacketWriter } from "wow/protocol/packet";
  4→import { GameOpcode, ChatType, ChannelNotify } from "wow/protocol/opcodes";
  5→import { sessionKey, serverSeed, FIXTURE_CHARACTER } from "test/fixtures";
  6→
  7→const ENCRYPT_KEY = "C2B3723CC6AED9B5343C53EE2F4367CE";
  8→const DECRYPT_KEY = "REDACTED";
  9→
 10→type ConnState = {
 11→  buf: Uint8Array;
 12→  arc4?: ServerArc4;
 13→  pendingHeader?: { size: number; opcode: number };
 14→};
 15→
 16→class ServerArc4 {
 17→  private encCipher: ReturnType<typeof createCipheriv>;
 18→  private decCipher: ReturnType<typeof createDecipheriv>;
 19→
 20→  constructor(key: Uint8Array) {
 21→    const encKey = createHmac("sha1", Buffer.from(DECRYPT_KEY, "hex"))
 22→      .update(key)
 23→      .digest();
 24→    const decKey = createHmac("sha1", Buffer.from(ENCRYPT_KEY, "hex"))
 25→      .update(key)
 26→      .digest();
 27→
 28→    this.encCipher = createCipheriv("rc4", encKey, "");
 29→    this.decCipher = createDecipheriv("rc4", decKey, "");
 30→
 31→    const drop = new Uint8Array(1024);
 32→    this.encCipher.update(drop);
 33→    this.decCipher.update(drop);
 34→  }
 35→
 36→  encrypt(data: Uint8Array): Uint8Array {
 37→    return new Uint8Array(this.encCipher.update(data));
 38→  }
 39→
 40→  decrypt(data: Uint8Array): Uint8Array {
 41→    return new Uint8Array(this.decCipher.update(data));
 42→  }
 43→}
 44→
 45→function buildServerPacket(
 46→  opcode: number,
 47→  body: Uint8Array,
 48→  arc4?: ServerArc4,
 49→): Uint8Array {
 50→  const header = new Uint8Array(4);
 51→  const view = new DataView(header.buffer);
 52→  view.setUint16(0, body.byteLength + 2, false);
 53→  view.setUint16(2, opcode, true);
 54→
 55→  const encrypted = arc4 ? arc4.encrypt(header) : header;
 56→  const packet = new Uint8Array(4 + body.byteLength);
 57→  packet.set(encrypted);
 58→  packet.set(body, 4);
 59→  return packet;
 60→}
 61→
 62→function decryptClientHeader(
 63→  header: Uint8Array,
 64→  arc4?: ServerArc4,
 65→): { size: number; opcode: number } {
 66→  const decrypted = arc4 ? arc4.decrypt(header) : header;
 67→  const view = new DataView(
 68→    decrypted.buffer,
 69→    decrypted.byteOffset,
 70→    decrypted.byteLength,
 71→  );
 72→  return { size: view.getUint16(0, false), opcode: view.getUint32(2, true) };
 73→}
 74→
 75→function send(
 76→  socket: Socket<ConnState>,
 77→  opcode: number,
 78→  body: Uint8Array,
 79→): void {
 80→  socket.write(buildServerPacket(opcode, body, socket.data.arc4));
 81→}
 82→
 83→function handleAuthSession(
 84→  socket: Socket<ConnState>,
 85→  authStatus: number,
 86→): void {
 87→  socket.data.arc4 = new ServerArc4(sessionKey);
 88→  send(socket, GameOpcode.SMSG_AUTH_RESPONSE, new Uint8Array([authStatus]));
 89→}
 90→
 91→function buildCharEnumBody(guildId = 0): Uint8Array {
 92→  const w = new PacketWriter(512);
 93→  w.uint8(1);
 94→  w.uint32LE(0x42);
 95→  w.uint32LE(0x00);
 96→  w.cString(FIXTURE_CHARACTER);
 97→  w.uint8(1);
 98→  w.uint8(1);
 99→  w.uint8(0);
100→  for (let i = 0; i < 5; i++) w.uint8(0);
101→  w.uint8(10);
102→  w.uint32LE(1);
103→  w.uint32LE(0);
104→  w.floatLE(0);
105→  w.floatLE(0);
106→  w.floatLE(0);
107→  w.uint32LE(guildId);
