          { ...base, host: "127.0.0.1", port: ws.port },
          fakeAuth(ws.port),
        );

        const firstEvent = new Promise<GuildEvent>((resolve) => {
          handle.onGuildEvent(resolve);
        });
        ws.inject(GameOpcode.SMSG_GUILD_ROSTER, buildGuildRosterPacket());
