          name: "Thrall",
          rankIndex: 0,
          level: 80,
          playerClass: 7,
          gender: 0,
          area: 10,
          status: 1,
          timeOffline: 0,
          publicNote: "",
          officerNote: "",
        },
      ],
    };
    (handle.requestGuildRoster as ReturnType<typeof jest.fn>).mockResolvedValue(
